insert into public.resort_activities (id, calendar_group_key, name, normalized_name, category, section, location, schedule_text, description, is_fee_based, is_daily, source_pdf_url) values (md5('act:all-star-movies:wellness-scavenger-hunt')::uuid, 'all-star-movies', 'Wellness Scavenger Hunt', 'wellness-scavenger-hunt', 'fitness_wellness'::public.activity_category, 'RESORT ACTIVITIES', 'Throughout Disney’s All-Star Resorts', 'Daily from 7:00am-11:00pm', 'Find hidden wellness challenges and partake in a scavenger hunt across all three of Disney’s All-Star Resorts. Pick up a map from Donald’s Double Feature to start exploring. Once you’ve finished the challenges, pick up a prize from any merchandise location at Disney’s All-Star Resorts.', false, true, 'https://cdn1.parksmedia.wdprapps.disney.com/vision-dam/digital/parks-platform/parks-global-assets/disney-world/recreation/guide/All-Star-Movies_Aframe_Recreation_1125.pdf');
