insert into public.resort_activities (id, calendar_group_key, name, normalized_name, category, section, location, schedule_text, description, is_fee_based, is_daily, source_pdf_url) values (md5('act:all-star-movies:arcade-tournament')::uuid, 'all-star-movies', 'Arcade Tournament', 'arcade-tournament', 'arcade'::public.activity_category, 'RESORT ACTIVITIES', 'Reel Fun Arcade', 'Daily from 4:00pm-5:00pm', 'Come test your skills at our daily arcade tournament. You may find yourself going home with a prize of your own! SORCERER’S CAMPFIRE Located between Fantasia Buildings 5 and 8 Daily from 6:00pm-7:00pm Enjoy the warm glow of the campfire with complimentary marshmallows. S’mores kits available for purchase.', false, true, 'https://cdn1.parksmedia.wdprapps.disney.com/vision-dam/digital/parks-platform/parks-global-assets/disney-world/recreation/guide/All-Star-Movies_Aframe_Recreation_1125.pdf');
