insert into public.resort_activities (id, calendar_group_key, name, normalized_name, category, section, location, schedule_text, description, is_fee_based, is_daily, source_pdf_url) values (md5('act:all-star-movies:all-star-lobby-party')::uuid, 'all-star-movies', 'All-Star Lobby Party', 'all-star-lobby-party', 'resort_activity'::public.activity_category, 'RESORT ACTIVITIES', 'Cinema Hall Lobby', 'Thursday and Saturday at 8:00pm', 'Wear your favorite pajamas for games, dancing and more surprise fun as we close out the evening. ($) There is a fee associated with this activity. Hours of operation, lifeguard availability, and other offerings are subject to closures, weather conditions, and change or cancellation without notice. 1125', true, false, 'https://cdn1.parksmedia.wdprapps.disney.com/vision-dam/digital/parks-platform/parks-global-assets/disney-world/recreation/guide/All-Star-Movies_Aframe_Recreation_1125.pdf');
