insert into public.resort_activities (id, calendar_group_key, name, normalized_name, category, section, location, schedule_text, description, is_fee_based, is_daily, source_pdf_url) values (md5('act:all-star-music:find-a-friend')::uuid, 'all-star-music', 'Find A Friend', 'find-a-friend', 'resort_activity'::public.activity_category, 'RESORT ACTIVITIES', 'Throughout Disney’s All-Star Resorts', 'Daily from 8:00am-9:00pm', 'Search the Resort for a hidden Goofy photo prop. Once located, snap a photo and then head to the Front Desk to receive a surprise!', false, true, 'https://cdn1.parksmedia.wdprapps.disney.com/vision-dam/digital/parks-services/services-standard-assets/ops-comm/wdw-csd/resort-collateral/recreation/fy26-q1/All-Star-Music_Aframe_Recreation_0126-V3_DRAFT.pdf');
