insert into public.resort_activities (id, calendar_group_key, name, normalized_name, category, section, location, schedule_text, description, is_fee_based, is_daily, source_pdf_url) values (md5('act:all-star-music:design-your-own-mosaic')::uuid, 'all-star-music', 'Design Your Own Mosaic', 'design-your-own-mosaic', 'arts_crafts'::public.activity_category, 'SIGNATURE ACTIVITIES', 'Intermission Food Court', 'Saturday at 1:00pm', 'Create a beautiful mosaic with Disney flair to remind you of your visit to the Walt Disney World® Resort. Please arrive 15 minutes prior to the start time to register. This experience is recommended for Guests ages 12 and up. Space is limited.', true, false, 'https://cdn1.parksmedia.wdprapps.disney.com/vision-dam/digital/parks-services/services-standard-assets/ops-comm/wdw-csd/resort-collateral/recreation/fy26-q1/All-Star-Music_Aframe_Recreation_0126-V3_DRAFT.pdf');
